import React, { useEffect, useState } from 'react';

export default function HistoricoSCM({ cnpj }) {
  const historicoKey = `historicoSCM_${cnpj}`;
  const [historico, setHistorico] = useState([]);

  useEffect(() => {
    try {
      const salvo = localStorage.getItem(historicoKey);
      setHistorico(salvo ? JSON.parse(salvo) : []);
    } catch {
      setHistorico([]);
    }
    // Atualiza ao mudar o localStorage em outras abas
    function atualizar() {
      try {
        const salvo = localStorage.getItem(historicoKey);
        setHistorico(salvo ? JSON.parse(salvo) : []);
      } catch {
        setHistorico([]);
      }
    }
    window.addEventListener('storage', atualizar);
    return () => window.removeEventListener('storage', atualizar);
  }, [historicoKey]);

  const handleExcluir = idx => {
    const novo = historico.filter((_, i) => i !== idx);
    setHistorico(novo);
    localStorage.setItem(historicoKey, JSON.stringify(novo));
  };

  if (!cnpj) return null;

  return (
    <div style={{width:'100%'}}>
      <h4 style={{marginBottom:12, color:'#1976d2', fontWeight:800, fontSize:18}}>Histórico SCM</h4>
      {historico.length === 0 ? (
        <div style={{color:'#888', fontSize:14}}>Nenhum arquivo gerado ainda.</div>
      ) : (
        <ul style={{paddingLeft:0, listStyle:'none', width:'100%'}}>
          {historico.map((h, idx) => (
            <li key={idx} style={{marginBottom:10, fontSize:15, display:'flex', alignItems:'center', gap:8, justifyContent:'space-between'}}>
              <div style={{display:'flex', flexDirection:'column'}}>
                <span style={{fontWeight:600}}>{h.nome}</span>
                <span style={{color:'#888', fontSize:12}}>{h.data}</span>
              </div>
              <div style={{display:'flex', gap:6}}>
                <button style={{background:'#1976d2', color:'#fff', border:'none', borderRadius:3, padding:'2px 10px', fontSize:13, cursor:'pointer'}}
                  title="Baixar este CSV"
                  onClick={() => {
                    const blob = new Blob([h.conteudo], { type: 'text/csv;charset=utf-8;' });
                    const url = URL.createObjectURL(blob);
                    const link = document.createElement('a');
                    link.href = url;
                    link.setAttribute('download', h.nome);
                    document.body.appendChild(link);
                    link.click();
                    document.body.removeChild(link);
                    URL.revokeObjectURL(url);
                  }}
                >Baixar</button>
                <button style={{background:'#e53935', color:'#fff', border:'none', borderRadius:3, padding:'2px 10px', fontSize:13, cursor:'pointer'}}
                  title="Excluir este CSV do histórico"
                  onClick={() => handleExcluir(idx)}
                >Excluir</button>
              </div>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}
